/bin/bash -lc "python - <<'PY'
import requests,pathlib
base='https://huggingface.co/datasets/songlab/TraitGym/resolve/main/'
files=[]
for ds in ['complex_traits_v22_matched_9','mendelian_traits_v22_matched_9']:
 for f in ['CADD.parquet','GPN-MSA_absLLR.parquet','GPN-MSA_LLR.parquet','Borzoi_L2_L2.parquet']:
  files.append(f'{ds}/features/{f}')
# Full Borzoi tensors for the complex-trait train and test sets.
for ds in ['complex_traits_v22_matched_9','complex_traits_matched_9']:
 files.append(f'{ds}/features/Borzoi_L2.parquet')
for p in files:
 out=pathlib.Path('data/traitgym')/p.replace('/','__')
 if out.exists() and out.stat().st_size>1000:
  print('exists',p,out.stat().st_size); continue
 with requests.get(base+p,stream=True,timeout=300) as r:
  print('start',p,r.status_code,r.headers.get('content-length'),flush=True); r.raise_for_status()
  with out.open('wb') as f:
   n=0
   for chunk in r.iter_content(8<<20):
    f.write(chunk); n+=len(chunk)
    if n//(100<<20)"'!=(n-len(chunk))//(100<<20):print('"' ',n,flush=True)
  print('done',p,n,flush=True)
PY"

